import { useState, useEffect } from "react";
import AdminLayout from "../../AdminLayout";
import "./AddPatient.css";

export default function AddPatient() {
  const [dob, setDob] = useState("");
  const [age, setAge] = useState("");

  useEffect(() => {
    if (!dob) return;
    const birth = new Date(dob);
    const today = new Date();
    let a = today.getFullYear() - birth.getFullYear();
    const m = today.getMonth() - birth.getMonth();
    if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) a--;
    setAge(a);
  }, [dob]);

  return (
    <AdminLayout>
      <div className="patient-wrapper">
        <h2>Patient Registration</h2>
        <p className="sub">HL7 v2.5 • ADT A04</p>

        <div className="patient-card">

          {/* PHOTO */}
          {/* <div className="photo-fixed">
            <div className="avatar"></div>
            <span>Upload Photo</span>
          </div> */
          }

          {/* PATIENT INFO */}
          <section>
            <h3>Patient Information</h3>
            <div className="form-grid">
              <Field label="MRN" />
              <Field label="First Name" />
              <Field label="Last Name" />
              <Field label="Display Name" />
              <Field label="Date of Birth" type="date" onChange={setDob} />
              <Field label="Age" value={age} disabled />
              <Select label="Gender" options={["Male", "Female"]} />
              <Select label="Marital Status" options={["Single", "Married"]} />
            </div>
          </section>

          {/* CONTACT */}
          <section>
            <h3>Contact Details</h3>
            <div className="form-grid">
              <Field label="Address" />
              <Select label="Country" options={["India", "UAE", "USA"]} />
              <Select label="City" options={["Delhi", "Mumbai", "Bangalore"]} />
              <Field label="Mobile Number" />
              <Field label="National ID Number" />
            </div>
          </section>

          {/* IDENTIFICATION */}
          <section>
            <h3>Patient Identification</h3>
            <div className="form-grid">
              <Select
                label="ID Type"
                options={[
                  "Aadhaar Card",
                  "Passport",
                  "PAN Card",
                  "Voter ID",
                  "Driving License",
                ]}
              />
              <Field label="ID Number" />
              <Field label="Expiry Date" type="date" />
              <div className="scan">
                <label>Scan ID</label>
                <button>Scan / Upload</button>
              </div>
            </div>
          </section>

          {/* EMERGENCY */}
          <section>
            <h3>Emergency Contact</h3>
            <div className="form-grid">
              <Field label="First Name" />
              <Field label="Last Name" />
              <Select
                label="Relationship"
                options={[
                  "Father",
                  "Mother",
                  "Brother",
                  "Sister",
                  "Husband",
                  "Cousin",
                  "Other",
                ]}
              />
              <Field label="Mobile Number" />
              <Select label="ID Type" options={["Aadhaar", "Passport", "PAN"]} />
              <Field label="ID Number" />
              <Field label="Expiry Date" type="date" />
            </div>
          </section>

          <div className="actions">
            <button>Register Patient</button>
          </div>
        </div>
      </div>
    </AdminLayout>
  );
}

const Field = ({ label, type = "text", value, disabled, onChange }) => (
  <div className="field">
    <label>{label}</label>
    <input
      type={type}
      value={value}
      disabled={disabled}
      onChange={(e) => onChange?.(e.target.value)}
    />
  </div>
);

const Select = ({ label, options }) => (
  <div className="field">
    <label>{label}</label>
    <select>
      {options.map((o) => (
        <option key={o}>{o}</option>
      ))}
    </select>
  </div>
);
